from dataclasses import dataclass, field, asdict
from datetime import datetime
import json

@dataclass
class Address:
    street: str
    city: str
    zip_code: str

@dataclass
class User:
    name: str
    email: str
    address: Address
    created_at: datetime = field(default_factory=datetime.now)
    tags: list[str] = field(default_factory=list)

    def to_json(self) -> str:
        def serializer(obj):
            if isinstance(obj, datetime):
                return obj.isoformat()
            raise TypeError(f'Not serializable: {type(obj)}')
        return json.dumps(asdict(self), default=serializer, indent=2)

    @classmethod
    def from_json(cls, json_str: str) -> 'User':
        data = json.loads(json_str)
        data['address'] = Address(**data['address'])
        data['created_at'] = datetime.fromisoformat(data['created_at'])
        return cls(**data)

from dataclasses import dataclass, field
from typing import Callable, Any

@dataclass
class Transition:
    event: str
    source: str
    target: str
    guard: Callable[..., bool] | None = None
    action: Callable[..., Any] | None = None

class StateMachine:
    def __init__(self, initial: str, transitions: list[Transition]):
        self.state = initial
        self._transitions: dict[tuple[str, str], Transition] = {}
        self._on_enter: dict[str, list[Callable]] = {}
        for t in transitions:
            self._transitions[(t.source, t.event)] = t

    def on_enter(self, state: str, callback: Callable):
        self._on_enter.setdefault(state, []).append(callback)

    def send(self, event: str, **ctx) -> bool:
        key = (self.state, event)
        t = self._transitions.get(key)
        if not t:
            return False
        if t.guard and not t.guard(**ctx):
            return False
        if t.action:
            t.action(**ctx)
        self.state = t.target
        for cb in self._on_enter.get(self.state, []):
            cb(**ctx)
        return True

# Usage:
# sm = StateMachine('idle', [
#     Transition('start', 'idle', 'running'),
#     Transition('pause', 'running', 'paused'),
#     Transition('resume', 'paused', 'running'),
#     Transition('stop', 'running', 'idle'),
# ])
